import{_ as o,c as t,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Журнал изменений: История версий | opencode-md-table-formatter","description":"Узнайте о развитии версий opencode-md-table-formatter и новых функциях. Ознакомьтесь с возможностями v0.1.0, включая автоматическое форматирование и кеширование ширины.","frontmatter":{"title":"Журнал изменений: История версий | opencode-md-table-formatter","sidebarTitle":"Обзор изменений версий","subtitle":"Журнал изменений: История версий и запись изменений","description":"Узнайте о развитии версий opencode-md-table-formatter и новых функциях. Ознакомьтесь с возможностями v0.1.0, включая автоматическое форматирование и кеширование ширины.","tags":["changelog","version-history","release-notes"],"prerequisite":[],"order":90},"headers":[],"relativePath":"ru/franlol/opencode-md-table-formatter/changelog/release-notes/index.md","filePath":"ru/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"}'),a={name:"ru/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"};function i(n,e,s,d,c,g){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="журнал-изменении-история-версии-и-запись-изменении" tabindex="-1">Журнал изменений: История версий и запись изменений <a class="header-anchor" href="#журнал-изменении-история-версии-и-запись-изменении" aria-label="Permalink to &quot;Журнал изменений: История версий и запись изменений&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Чему вы научитесь</p><ul><li>Отслеживать эволюцию версий плагина</li><li>Узнавать о новых функциях и исправлениях в каждой версии</li><li>Освоить известные ограничения и технические детали</li><li>Понять возможные будущие улучшения функциональности</li></ul></div><hr><h2 id="_0-1-0-2025-01-07" tabindex="-1">[0.1.0] - 2025-01-07 <a class="header-anchor" href="#_0-1-0-2025-01-07" aria-label="Permalink to &quot;[0.1.0] - 2025-01-07&quot;">​</a></h2><h3 id="новые-возможности" tabindex="-1">Новые возможности <a class="header-anchor" href="#новые-возможности" aria-label="Permalink to &quot;Новые возможности&quot;">​</a></h3><p>Это <strong>начальный релиз</strong> opencode-md-table-formatter, содержащий следующие основные функции:</p><ul><li><strong>Автоматическое форматирование таблиц</strong>: Автоматическое форматирование Markdown-таблиц, сгенерированных ИИ, через хук <code>experimental.text.complete</code></li><li><strong>Поддержка скрытого режима</strong>: Правильная обработка скрытых Markdown-символов (например, <code>**</code>, <code>*</code>) при вычислении ширины</li><li><strong>Обработка вложенного Markdown</strong>: Поддержка вложенного Markdown-синтаксиса произвольной глубины с использованием многошагового алгоритма удаления</li><li><strong>Защита блоков кода</strong>: Markdown-символы внутри встроенного кода (<code>`code`</code>) сохраняются в буквальном виде и не участвуют в вычислении ширины</li><li><strong>Поддержка выравнивания</strong>: Поддержка левого выравнивания (<code>---</code> или <code>:---</code>), центрирования (<code>:---:</code>), правого выравнивания (<code>---:</code>)</li><li><strong>Оптимизация кеширования ширины</strong>: Кеширование результатов вычисления ширины отображения строк для повышения производительности</li><li><strong>Проверка неверных таблиц</strong>: Автоматическая проверка структуры таблиц, недействительные таблицы получают комментарии об ошибках</li><li><strong>Поддержка нескольких символов</strong>: Поддержка Emoji, Unicode-символов, пустых ячеек, сверхдлинного содержимого</li><li><strong>Тихая обработка ошибок</strong>: Ошибки форматирования не прерывают рабочий процесс OpenCode</li></ul><h3 id="технические-детали" tabindex="-1">Технические детали <a class="header-anchor" href="#технические-детали" aria-label="Permalink to &quot;Технические детали&quot;">​</a></h3><p>Эта версия содержит примерно <strong>230 строк производственного кода на TypeScript</strong>:</p><ul><li><strong>12 функций</strong>: Чёткое разделение обязанностей, хорошая изоляция</li><li><strong>Безопасность типов</strong>: Правильное использование интерфейса <code>Hooks</code></li><li><strong>Интеллектуальная очистка кеша</strong>: Очистка срабатывает при превышении 100 операций или 1000 записей в кеше</li><li><strong>Многошаговая обработка регулярными выражениями</strong>: Поддержка удаления Markdown-символов произвольной вложенности</li></ul><div class="tip custom-block"><p class="custom-block-title">Механизм кеширования</p><p>Кеш разработан для оптимизации вычисления ширины повторяющегося содержимого. Например, когда один и тот же текст ячейки появляется в таблице несколько раз, ширина вычисляется только один раз, а последующие чтения берутся из кеша.</p></div><h3 id="известные-ограничения" tabindex="-1">Известные ограничения <a class="header-anchor" href="#известные-ограничения" aria-label="Permalink to &quot;Известные ограничения&quot;">​</a></h3><p>Эта версия не поддерживает следующие сценарии:</p><ul><li><strong>HTML-таблицы</strong>: Поддерживаются только Markdown-таблицы с разделителями (Pipe Table)</li><li><strong>Многострочные ячейки</strong>: Ячейки, содержащие теги <code>&lt;br&gt;</code>, не поддерживаются</li><li><strong>Таблицы без строки-разделителя</strong>: Таблица должна содержать строку-разделитель (<code>|---|</code>) для форматирования</li><li><strong>Требования к зависимостям</strong>: Требуется <code>@opencode-ai/plugin</code> &gt;= 0.13.7 (используется неопубликованный хук <code>experimental.text.complete</code>)</li></ul><div class="info custom-block"><p class="custom-block-title">Требования к версии</p><p>Плагин требует OpenCode &gt;= 1.0.137 и <code>@opencode-ai/plugin</code> &gt;= 0.13.7 для правильной работы.</p></div><hr><h2 id="будущие-планы" tabindex="-1">Будущие планы <a class="header-anchor" href="#будущие-планы" aria-label="Permalink to &quot;Будущие планы&quot;">​</a></h2><p>Следующие функции планируются к реализации в будущих версиях:</p><ul><li><strong>Параметры конфигурации</strong>: Поддержка пользовательских минимальной/максимальной ширины столбцов, отключение определённых функций</li><li><strong>Поддержка таблиц без заголовка</strong>: Форматирование таблиц без строки заголовка</li><li><strong>Оптимизация производительности</strong>: Анализ и оптимизация производительности для очень больших таблиц (100+ строк)</li><li><strong>Больше вариантов выравнивания</strong>: Расширение синтаксиса и функциональности выравнивания</li></ul><div class="tip custom-block"><p class="custom-block-title">Участие в разработке</p><p>Если у вас есть предложения по функциональности или вы хотите внести код, пожалуйста, поделитесь своими идеями в <a href="https://github.com/franlol/opencode-md-table-formatter/issues" target="_blank" rel="noreferrer">GitHub Issues</a>.</p></div><hr><h2 id="описание-формата-журнала-изменении" tabindex="-1">Описание формата журнала изменений <a class="header-anchor" href="#описание-формата-журнала-изменении" aria-label="Permalink to &quot;Описание формата журнала изменений&quot;">​</a></h2><p>Журнал изменений этого проекта следует формату <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, а номера версий следуют <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Семантической спецификации версий (Semantic Versioning)</a>.</p><p><strong>Формат номера версии</strong>: <code>MAJOR.MINOR.PATCH</code></p><ul><li><strong>MAJOR</strong>: Несовместимые изменения API</li><li><strong>MINOR</strong>: Новая функциональность с обратной совместимостью</li><li><strong>PATCH</strong>: Исправления с обратной совместимостью</li></ul><p><strong>Типы изменений</strong>:</p><ul><li><strong>Added</strong>: Добавленные функции</li><li><strong>Changed</strong>: Изменения существующей функциональности</li><li><strong>Deprecated</strong>: Функции, которые будут удалены</li><li><strong>Removed</strong>: Удалённые функции</li><li><strong>Fixed</strong>: Исправления проблем</li><li><strong>Security</strong>: Исправления, связанные с безопасностью</li></ul><hr><h2 id="рекомендуемыи-порядок-чтения" tabindex="-1">Рекомендуемый порядок чтения <a class="header-anchor" href="#рекомендуемыи-порядок-чтения" aria-label="Permalink to &quot;Рекомендуемый порядок чтения&quot;">​</a></h2><p>Если вы новый пользователь, рекомендуем изучать в следующем порядке:</p><ol><li><a href="./../../start/getting-started/">Быстрый старт: Установка и конфигурация</a> — Быстрое начало работы</li><li><a href="./../../start/features/">Обзор функций: Магия автоматического форматирования</a> — Понимание основных функций</li><li><a href="./../../faq/troubleshooting/">Часто задаваемые вопросы: Что делать, если таблица не форматируется</a> — Устранение неполадок</li><li><a href="./../../appendix/limitations/">Известные ограничения: Где находятся границы плагина</a> — Понимание ограничений</li></ol>',31)])])}const u=o(a,[["render",i]]);export{h as __pageData,u as default};
